import{_ as e,o as p,c as t,ah as r}from"./chunks/framework.D-EW4Mou.js";const _=JSON.parse('{"title":"协议栈","description":"","frontmatter":{},"headers":[],"relativePath":"kernel/linux/net/stack.md","filePath":"kernel/linux/net/stack.md"}'),n={name:"kernel/linux/net/stack.md"};function s(i,a,l,o,c,h){return p(),t("div",null,[...a[0]||(a[0]=[r('<h1 id="协议栈" tabindex="-1">协议栈 <a class="header-anchor" href="#协议栈" aria-label="Permalink to “协议栈”">​</a></h1><p>sk_buff：Linux 网络的核心载体</p><p>所有网络数据在内核中都封装为 struct sk_buff（skb）。</p><p>skb 是一个高度优化的包描述符：</p><p>头部指针分层推进（mac_header / network_header / transport_header）</p><p>支持 clone（零拷贝）</p><p>支持 scatter-gather</p><p>支持 GSO/GRO</p><p>理解 skb 的生命周期，是理解 Linux 网络性能的关键。</p><p>数据路径本质上是 skb 在不同子系统之间移动。</p><h2 id="防火墙" tabindex="-1">防火墙 <a class="header-anchor" href="#防火墙" aria-label="Permalink to “防火墙”">​</a></h2><p>netfilter 框架</p><h2 id="路由子系统" tabindex="-1">路由子系统 <a class="header-anchor" href="#路由子系统" aria-label="Permalink to “路由子系统”">​</a></h2><h2 id="邻居子系统" tabindex="-1">邻居子系统 <a class="header-anchor" href="#邻居子系统" aria-label="Permalink to “邻居子系统”">​</a></h2><p>路由与邻居子系统</p><p>Linux 路由查找基于 FIB（Forwarding Information Base）。</p><p>最长前缀匹配</p><p>支持多表</p><p>支持策略路由（RPDB）</p><p>ARP 属于邻居子系统（neigh）。</p><p>ARP 表并不是简单缓存，而是状态机：</p><p>INCOMPLETE → REACHABLE → STALE → DELAY → PROBE</p><p>理解这个状态机，才能理解 ARP 抖动和丢包现象。</p><p>Netfilter 与 nftables</p><p>Netfilter 在五个关键 hook 点插入逻辑：</p><p>PREROUTING</p><p>INPUT</p><p>FORWARD</p><p>OUTPUT</p><p>POSTROUTING</p><p>iptables 是历史接口。 现代系统推荐使用 nftables。</p><p>NAT 本质是连接跟踪（conntrack）驱动的地址重写。</p><p>没有 conntrack，就没有状态 NAT。</p><p>性能瓶颈往往出现在 conntrack 表。</p>',34)])])}const k=e(n,[["render",s]]);export{_ as __pageData,k as default};
